    require(
        _lastGaugeLossApplied >= _lastGaugeLoss,
        "GuildToken: pending loss"
    );
    // ...
}
```

2. This check is performed in the `transfer` and `transferFrom` functions, regardless of the amount being transferred or its relationship to the loss-suffering gauge:

```solidity
function transfer(
    address to,
    uint256 amount
)
    public
    virtual
    override(ERC20, ERC20Gauges, ERC20MultiVotes)
    returns (bool)
{
    _decrementWeightUntilFree(msg.sender, amount);
    _decrementVotesUntilFree(msg.sender, amount);
    return ERC20.transfer(to, amount);
}

function transferFrom(
    address from,
